/**
 * Solves Kepler's equation using Newton-Raphson iteration
 */
export function solveKepler(M: number, e: number, tol: number = 1e-8): number {
  let E = M;
  for (let i = 0; i < 100; i++) {
    const dE = (E - e * Math.sin(E) - M) / (1 - e * Math.cos(E));
    E -= dE;
    if (Math.abs(dE) < tol) break;
  }
  return E;
}

